-- Synthetic Learn with Sabih dataset (interactive CS study guide) for SQL teaching. Fully synthetic.
-- Generated reproducibly with seed = 42.

DROP TABLE IF EXISTS events;
DROP TABLE IF EXISTS sessions;
DROP TABLE IF EXISTS users;

CREATE TABLE users (
    user_id     INTEGER PRIMARY KEY,
    signup_date DATE NOT NULL,
    country     TEXT NOT NULL,
    plan        TEXT NOT NULL CHECK (plan IN ('free', 'pro'))
);

CREATE TABLE sessions (
    session_id INTEGER PRIMARY KEY,
    user_id    INTEGER NOT NULL REFERENCES users(user_id),
    started_at TIMESTAMP NOT NULL
);

CREATE TABLE events (
    event_id    INTEGER PRIMARY KEY,
    session_id  INTEGER NOT NULL REFERENCES sessions(session_id),
    user_id     INTEGER NOT NULL REFERENCES users(user_id),
    event       TEXT NOT NULL CHECK (event IN ('topic_opened', 'interactive_used', 'topic_completed')),
    occurred_at TIMESTAMP NOT NULL
);

